// src/App.jsx
import { useState } from "react";
import "./styles/global.css";
import { AuthProvider, useAuth } from "./hooks/useAuth";
import { Spinner } from "./components/shared/index.jsx";
import LoginPage from "./components/auth/LoginPage.jsx";
import { Sidebar, Topbar } from "./components/layout/index.jsx";

// Intern pages
import { InternDashboard, MyTasksPage, ProfilePage } from "./pages/intern/index.jsx";

// Supervisor pages
import { SupervisorDashboard, AllTasksPage, InternsPage, ProjectsPage } from "./pages/supervisor/index.jsx";

// Shared
import ReportPage from "./pages/shared/ReportPage.jsx";

function AppShell() {
  const { user, loading } = useAuth();
  const [page, setPage]   = useState("dashboard");

  if (loading) return <Spinner/>;
  if (!user)   return <LoginPage/>;

  const renderPage = () => {
    if (user.role === "intern") {
      if (page==="dashboard") return <InternDashboard/>;
      if (page==="mytasks")   return <MyTasksPage/>;
      if (page==="profile")   return <ProfilePage/>;
      if (page==="report")    return <ReportPage/>;
      return <InternDashboard/>;
    }
    if (page==="dashboard") return <SupervisorDashboard/>;
    if (page==="tasks")     return <AllTasksPage/>;
    if (page==="interns")   return <InternsPage/>;
    if (page==="projects")  return <ProjectsPage/>;
    if (page==="report")    return <ReportPage/>;
    return <SupervisorDashboard/>;
  };

  return (
    <div style={{ display:"flex", minHeight:"100vh" }}>
      <Sidebar page={page} setPage={setPage}/>
      <main style={{ marginLeft:"var(--sidebar-w)", flex:1, display:"flex", flexDirection:"column", minHeight:"100vh", background:"var(--gray-50)" }}>
        <Topbar page={page}/>
        <div style={{ padding:"28px 32px", flex:1 }}>
          {renderPage()}
        </div>
      </main>
    </div>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <AppShell/>
    </AuthProvider>
  );
}
